<h3 className="">{`Inline forms`}</h3>
{`
`}
<p className="">{`Use the `}
<code className="">{`inline`}</code>
{` property to display a series of labels, form controls, and buttons on a single horizontal row.
Form controls within inline forms vary slightly from their default states.`}</p>
{`
`}
<ul className="">{`
`}
<li className="">{`Controls are `}
<code className="">{`display: flex`}</code>
{`, collapsing any HTML white space and allowing you to provide alignment control with `}
<a href="https://getbootstrap.com/docs/4.5/utilities/spacing/" className="">{`spacing`}</a>
{` and `}
<a href="https://getbootstrap.com/docs/4.5/utilities/flex/" className="">{`flexbox`}</a>
{` utilities.`}</li>
{`
`}
<li className="">{`Controls and input groups receive `}
<code className="">{`width: auto`}</code>
{` to override the Bootstrap default `}
<code className="">{`width: 100%`}</code>
{`.`}</li>
{`
`}
<li className="">{`Controls `}
<strong className="">{`only appear inline in viewports that are at least 576px`}</strong>
{` wide to account for narrow viewports on mobile devices.`}</li>
{`
`}</ul>
{`
`}
<p className="">{`You may need to manually address the width and alignment of individual form controls with `}
<a href="https://getbootstrap.com/docs/4.5/utilities/spacing/" className="">{`spacing utilities`}</a>
{` (as shown below).`}</p>
{`
`}
<Example>
    <Form inline>
        <FormField is="select" label="Preference" className="mr-sm-2">
            <option selected>Choose...</option>
            {['One', 'Two', 'Three'].map((text, index) => (
                <option value={index + 1}>{text}</option>
            ))}
        </FormField>
        <ToggleField type="checkbox" className="mr-sm-2">
            Remember my preference
        </ToggleField>
        <Button type="submit" color="primary">
            Submit
        </Button>
    </Form>
</Example>
